code = """import json

# Get the file path for reviews
key = 'var_functions.query_db:48'
file_path = locals()[key]

# Load JSON data from the file
with open(file_path, 'r') as f:
    reviews = json.load(f)

print(f"Total reviews loaded: {len(reviews)}")

# Business refs for Pennsylvania WiFi businesses
pa_business_refs = ['businessref_89', 'businessref_97', 'businessref_67', 'businessref_77', 
                    'businessref_86', 'businessref_40', 'businessref_44', 'businessref_82']

# Filter reviews for Pennsylvania businesses
pa_reviews = [review for review in reviews if review['business_ref'] in pa_business_refs]
print(f"Reviews for Pennsylvania WiFi businesses: {len(pa_reviews)}")

# Extract ratings (convert strings to integers)
ratings = [int(review['rating']) for review in pa_reviews]
print(f"Ratings count: {len(ratings)}")
print(f"First 10 ratings: {ratings[:10]}")

# Calculate average rating
if ratings:
    avg_rating = sum(ratings) / len(ratings)
    print(f"Average rating: {avg_rating:.2f}")
    print(f"Min rating: {min(ratings)}")
    print(f"Max rating: {max(ratings)}")
else:
    avg_rating = 0
    print("No ratings found")

result = {
    'total_reviews': len(reviews),
    'pa_reviews_count': len(pa_reviews),
    'ratings_count': len(ratings),
    'average_rating': round(avg_rating, 2),
    'min_rating': min(ratings) if ratings else 0,
    'max_rating': max(ratings) if ratings else 0
}

print('__RESULT__:')
print(json.dumps(result))"""

